parameters.jsCode:
const body = $json.body || {};

const evento = String(body.evento || 'indefinido');
const tentativas = Number(body.tentativas || 0);
const janela = Number(body.janela_minutos || 0);

let prioridade = 'baixa';
let acao = 'Monitorar e registrar evento.';

if (tentativas >= 200 || /ransomware|exfiltracao|credential_stuffing/i.test(evento)) {
  prioridade = 'alta';
  acao = 'Escalonar imediatamente para N2 e bloquear origem de ataque.';
} else if (tentativas >= 50 || /phishing|bruteforce|anomalia/i.test(evento)) {
  prioridade = 'media';
  acao = 'Abrir ticket, aplicar contenção inicial e acompanhar.';
}

return [{
  json: {
    ok: true,
    workflow: '05_agente_n8n_soc_webhook',
    entrada: body,
    analise: {
      prioridade,
      acao_recomendada: acao,
      score_risco: Math.min(100, Math.round((tentativas * 0.3) + (janela * 0.8))),
      resumo: `Evento ${evento} em ${body.host || 'host_desconhecido'} para ${body.usuario_alvo || 'usuario_desconhecido'}.`
    },
    processado_em: new Date().toISOString()
  }
}];

