parameters.jsCode:
const risco = $('Code - Classificar Risco').first().json;

let playbook = {};
const raw = $('Gemini - Playbook Resposta').first()?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '';

if (raw) {
  try {
    const limpo = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    playbook = JSON.parse(limpo);
  } catch (e) {
    playbook = { erro: 'Parse gemini', detalhes: raw };
  }
} else {
  playbook = { erro: 'Sem resposta Gemini', detalhes: $('Gemini - Playbook Resposta').first()?.json || {} };
}

return [{
  json: {
    ok: true,
    entrada: risco.entrada,
    classificacao: risco.analise,
    playbook: playbook,
    processado_em: new Date().toISOString(),
    workflow: '05_agente_n8n_soc_webhook_v2_gemini'
  }
}];
